import {
  SET_X,
  SET_Y,
  SET_R,
  SET_RESULTS,
  ADD_RESULT
} from './appTypes';


export const setX = value => ({
  type: SET_X,
  payload: value
});

export const setY = value => ({
  type: SET_Y,
  payload: value
});

export const setR = value => ({
  type: SET_R,
  payload: value
});

export const setResults = result => ({
  type: SET_RESULTS,
  payload: result
});

export const addResult = result => ({
  type: ADD_RESULT,
  payload: result
});
